function Alert({ type }) {
  const baseClass = 'alert';
  const typeClass = type === 'error' ? 'alert-danger' : 'alert-info';
  return <div className={`${baseClass} ${typeClass}`}>Alert</div>;
}

// Or using an object map
const typeClasses = {
  error: 'alert-danger',
  success: 'alert-success',
  warning: 'alert-warning'
};

function Alert({ type }) {
  return <div className={`alert ${typeClasses[type] || 'alert-info'}`}>Alert</div>;
}
